<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover">
  <title>9×9 Go Board</title>
  <style>
    :root {
      color-scheme: light dark;
      --bg: #f4e4b2;
      --bg2: #e7c97d;
      --line: #6d4c1f;
      --shadow: rgba(0, 0, 0, 0.25);
      --black: #111;
      --white: #f7f4ec;
      --text: #1c1c1c;
      --panel: rgba(255, 255, 255, 0.55);
    }

    * { box-sizing: border-box; }
    html, body { height: 100%; margin: 0; }
    body {
      font-family: system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif;
      background:
        radial-gradient(circle at top, rgba(255,255,255,0.28), transparent 45%),
        linear-gradient(180deg, #f7e6b8, #e8c56f 70%, #d7ad57);
      color: var(--text);
      display: grid;
      place-items: center;
      padding: 16px;
    }

    .app {
      width: min(94vw, 820px);
      display: grid;
      gap: 14px;
      justify-items: center;
    }

    .topbar {
      width: 100%;
      display: flex;
      gap: 12px;
      flex-wrap: wrap;
      justify-content: space-between;
      align-items: center;
      padding: 12px 14px;
      border-radius: 18px;
      background: var(--panel);
      backdrop-filter: blur(10px);
      box-shadow: 0 12px 30px var(--shadow);
      border: 1px solid rgba(0,0,0,0.08);
    }

    .title {
      font-size: clamp(1.1rem, 2vw, 1.4rem);
      font-weight: 800;
      letter-spacing: 0.02em;
    }

    .status {
      display: flex;
      gap: 10px;
      align-items: center;
      flex-wrap: wrap;
      font-size: 0.95rem;
    }

    .pill {
      padding: 6px 10px;
      border-radius: 999px;
      background: rgba(255,255,255,0.65);
      border: 1px solid rgba(0,0,0,0.08);
      font-weight: 600;
    }

    button {
      font: inherit;
    }

    .btn {
      border: 0;
      border-radius: 999px;
      padding: 8px 14px;
      cursor: pointer;
      background: #222;
      color: #fff;
      box-shadow: 0 8px 18px rgba(0,0,0,0.18);
    }

    .btn.secondary { background: rgba(255,255,255,0.78); color: #222; }

    .board-wrap {
      width: min(94vw, 760px);
      aspect-ratio: 1;
      padding: clamp(12px, 2vw, 22px);
      border-radius: 28px;
      background:
        radial-gradient(circle at 50% 30%, rgba(255,255,255,0.35), transparent 50%),
        linear-gradient(180deg, var(--bg), var(--bg2));
      box-shadow:
        inset 0 1px 0 rgba(255,255,255,0.5),
        0 30px 60px rgba(0,0,0,0.22);
      border: 1px solid rgba(76, 51, 18, 0.18);
    }

    .board {
      position: relative;
      width: 100%;
      height: 100%;
      display: grid;
      grid-template-columns: repeat(9, 1fr);
      grid-template-rows: repeat(9, 1fr);
      background: transparent;
      user-select: none;
      touch-action: manipulation;
    }

    .board::before {
      content: "";
      position: absolute;
      inset: calc(50% / 9);
      border: 2px solid transparent;
      box-shadow:
        inset 0 0 0 2px rgba(109,76,31,0.85),
        inset 0 0 0 999px rgba(0,0,0,0.01);
      pointer-events: none;
    }

    .intersection {
      position: relative;
      cursor: pointer;
    }

    .intersection::before,
    .intersection::after {
      content: "";
      position: absolute;
      background: var(--line);
      opacity: 0.95;
      pointer-events: none;
    }

    .intersection::before {
      left: 50%; top: 0; bottom: 0;
      width: 2px; transform: translateX(-50%);
    }

    .intersection::after {
      top: 50%; left: 0; right: 0;
      height: 2px; transform: translateY(-50%);
    }

    .intersection[data-row="0"]::after { top: 50%; }
    .intersection[data-row="8"]::after { top: 50%; }
    .intersection[data-col="0"]::before { left: 50%; }
    .intersection[data-col="8"]::before { left: 50%; }

    .stone {
      position: absolute;
      left: 50%; top: 50%;
      width: 82%; height: 82%;
      transform: translate(-50%, -50%) scale(0.98);
      border-radius: 50%;
      box-shadow: 0 6px 10px rgba(0,0,0,0.24);
      pointer-events: none;
      z-index: 2;
    }

    .stone.black {
      background: radial-gradient(circle at 30% 30%, #555, #0b0b0b 56%, #000);
    }

    .stone.white {
      background: radial-gradient(circle at 30% 30%, #ffffff, #ece7dc 60%, #d9d0c1);
    }

    .intersection.star::before {
      background: transparent;
      box-shadow: 0 0 0 0 transparent;
    }

    .star {
      position: absolute;
      left: 50%; top: 50%;
      width: 10px; height: 10px;
      border-radius: 50%;
      transform: translate(-50%, -50%);
      background: var(--line);
      opacity: 0.95;
      pointer-events: none;
      z-index: 1;
    }

    .footer {
      font-size: 0.92rem;
      opacity: 0.85;
      text-align: center;
      max-width: 60ch;
      line-height: 1.45;
    }

    @media (max-width: 640px) {
      .topbar { justify-content: center; text-align: center; }
      .status { justify-content: center; }
    }
  </style>
</head>
<body>
  <div class="app">
    <div class="topbar">
      <div class="title">9×9 Go Board</div>
      <div class="status">
        <span class="pill" id="turnPill">Black to play</span>
        <span class="pill" id="capturesPill">Captures — B 0 / W 0</span>
        <button class="btn secondary" id="passBtn" type="button">Pass</button>
        <button class="btn secondary" id="undoBtn" type="button">Undo</button>
        <button class="btn" id="resetBtn" type="button">New game</button>
      </div>
    </div>

    <div class="board-wrap">
      <div class="board" id="board" aria-label="9 by 9 Go board" role="grid"></div>
    </div>

    <div class="footer" id="message">Click an intersection to play. Captures and simple ko are enforced; suicide is not allowed.</div>
  </div>

  <script>
    const SIZE = 9;
    const boardEl = document.getElementById('board');
    const turnPill = document.getElementById('turnPill');
    const capturesPill = document.getElementById('capturesPill');
    const messageEl = document.getElementById('message');
    const passBtn = document.getElementById('passBtn');
    const undoBtn = document.getElementById('undoBtn');
    const resetBtn = document.getElementById('resetBtn');

    const STAR_POINTS = new Set(['2,2', '2,6', '6,2', '6,6', '4,4']);
    let state;

    function newState() {
      return {
        board: Array.from({ length: SIZE }, () => Array(SIZE).fill(null)),
        turn: 'black',
        captures: { black: 0, white: 0 },
        history: [],
        ko: null,
      };
    }

    function cloneBoard(board) { return board.map(row => row.slice()); }
    function key(r, c) { return `${r},${c}`; }
    function inBounds(r, c) { return r >= 0 && r < SIZE && c >= 0 && c < SIZE; }
    function opponent(color) { return color === 'black' ? 'white' : 'black'; }

    function neighbors(r, c) {
      return [[r-1,c],[r+1,c],[r,c-1],[r,c+1]].filter(([rr,cc]) => inBounds(rr,cc));
    }

    function groupAt(board, r, c) {
      const color = board[r][c];
      const stack = [[r,c]];
      const group = [];
      const seen = new Set();
      let liberties = new Set();
      while (stack.length) {
        const [rr, cc] = stack.pop();
        const k = key(rr, cc);
        if (seen.has(k)) continue;
        seen.add(k);
        group.push([rr, cc]);
        for (const [nr, nc] of neighbors(rr, cc)) {
          const v = board[nr][nc];
          if (v === null) liberties.add(key(nr, nc));
          else if (v === color) stack.push([nr, nc]);
        }
      }
      return { color, stones: group, liberties };
    }

    function serialize(board) {
      return board.map(row => row.map(v => v ? v[0] : '.').join('')).join('/');
    }

    function render() {
      boardEl.innerHTML = '';
      for (let r = 0; r < SIZE; r++) {
        for (let c = 0; c < SIZE; c++) {
          const cell = document.createElement('button');
          cell.className = 'intersection';
          if (STAR_POINTS.has(key(r, c))) cell.classList.add('star');
          cell.type = 'button';
          cell.dataset.row = r;
          cell.dataset.col = c;
          cell.setAttribute('role', 'gridcell');
          const stone = state.board[r][c];
          if (stone) {
            const piece = document.createElement('div');
            piece.className = `stone ${stone}`;
            cell.appendChild(piece);
          }
          if (STAR_POINTS.has(key(r, c))) {
            const star = document.createElement('div');
            star.className = 'star';
            cell.appendChild(star);
          }
          cell.addEventListener('click', () => play(r, c));
          boardEl.appendChild(cell);
        }
      }
      turnPill.textContent = `${state.turn[0].toUpperCase()}${state.turn.slice(1)} to play`;
      capturesPill.textContent = `Captures — B ${state.captures.black} / W ${state.captures.white}`;
      passBtn.textContent = 'Pass';
    }

    function setMessage(text) { messageEl.textContent = text; }

    function play(r, c) {
      if (state.board[r][c] !== null) return setMessage('That point is occupied.');
      if (state.ko && state.ko === key(r, c)) return setMessage('Ko: that move is temporarily forbidden.');

      const next = cloneBoard(state.board);
      const color = state.turn;
      const enemy = opponent(color);
      next[r][c] = color;
      let captured = [];

      for (const [nr, nc] of neighbors(r, c)) {
        if (next[nr][nc] !== enemy) continue;
        const grp = groupAt(next, nr, nc);
        if (grp.liberties.size === 0) {
          captured.push(...grp.stones);
        }
      }
      if (captured.length) {
        for (const [rr, cc] of captured) next[rr][cc] = null;
      }

      const selfGroup = groupAt(next, r, c);
      if (selfGroup.liberties.size === 0) return setMessage('Illegal move: suicide is not allowed.');

      const prevBoard = serialize(state.board);
      const nextBoard = serialize(next);
      let ko = null;
      if (captured.length === 1) {
        const [cr, cc] = captured[0];
        const capturedGroup = groupAt(state.board, cr, cc);
        if (capturedGroup.stones.length === 1 && selfGroup.stones.length === 1) {
          const liberty = [...selfGroup.liberties][0];
          ko = liberty;
        }
      }
      if (ko && serialize(applyMovePreview(state.board, r, c, color)) === prevBoard) ko = null;

      state.history.push({ board: cloneBoard(state.board), turn: state.turn, captures: { ...state.captures }, ko: state.ko, message: messageEl.textContent });
      state.board = next;
      state.turn = enemy;
      state.ko = ko;
      if (captured.length) state.captures[color] += captured.length;
      setMessage(captured.length ? `${color[0].toUpperCase()}${color.slice(1)} captured ${captured.length}.` : `${color[0].toUpperCase()}${color.slice(1)} played.`);
      render();
    }

    function applyMovePreview(board, r, c, color) {
      const copy = cloneBoard(board);
      copy[r][c] = color;
      return copy;
    }

    function passTurn() {
      state.history.push({ board: cloneBoard(state.board), turn: state.turn, captures: { ...state.captures }, ko: state.ko, message: messageEl.textContent });
      state.turn = opponent(state.turn);
      state.ko = null;
      setMessage(`${state.turn[0].toUpperCase()}${state.turn.slice(1)} to play after a pass.`);
      render();
    }

    function undo() {
      const prev = state.history.pop();
      if (!prev) return setMessage('Nothing to undo.');
      state.board = prev.board;
      state.turn = prev.turn;
      state.captures = prev.captures;
      state.ko = prev.ko;
      setMessage(prev.message || 'Undone.');
      render();
    }

    function reset() {
      state = newState();
      setMessage('New game started. Black to play.');
      render();
    }

    passBtn.addEventListener('click', passTurn);
    undoBtn.addEventListener('click', undo);
    resetBtn.addEventListener('click', reset);

    reset();
  </script>
</body>
</html>
